const sources = $('Lookup Source ID').first().json?.data || [];
const items   = $input.all();
return items.map(item => {
  const src = sources.find(s => s.slug === item.json.source_slug);
  return { json: { ...item.json, source_id: src?.id ?? null } };
}).filter(i => {
  if (!i.json.source_id) console.warn('[STORAGE] unknown source_slug:', i.json.source_slug);
  return !!i.json.source_id;
});
